-- Resources
INSERT INTO public.resources (slug, title, summary, body, category, read_minutes, source, published) VALUES
('gestion-stress-manifestation',
  '{"en":"Managing Stress in High-Pressure Mobilization","fr":"Gérer le stress en mobilisation sous pression","mg":"Fitantanana ny adin-tsaina amin''ny hetsika sarotra"}'::jsonb,
  '{"en":"Practical breathing, grounding, and team-care techniques for marshals and participants.","fr":"Techniques pratiques de respiration, ancrage et soutien collectif pour marshals et participants.","mg":"Fomba fiainana sy fanampiana ho an''ny mpitarika sy mpandray anjara."}'::jsonb,
  '{"en":"# Stay Steady\n\nFear is information, not weakness. Use these tools:\n\n## 4-7-8 Breathing\nInhale 4s, hold 7s, exhale 8s. Repeat 4 cycles. Lowers heart rate within 90 seconds.\n\n## 5-4-3-2-1 Grounding\nName 5 things you see, 4 you touch, 3 you hear, 2 you smell, 1 you taste. Pulls you out of panic spirals.\n\n## Buddy Check-In\nEvery 30 minutes, look your buddy in the eye and ask: ''Body okay? Mind okay?'' Two questions, two honest answers.\n\n## After-Action Care\nDecompress within 24h. Hot shower, full meal, 8h sleep. Skip social media for 12h. Call the mental health hotline if intrusive thoughts persist.","fr":"# Restez ancré\n\nLa peur est une information, pas une faiblesse.\n\n## Respiration 4-7-8\nInspirez 4s, retenez 7s, expirez 8s. 4 cycles. Baisse le rythme cardiaque en 90 secondes.\n\n## Ancrage 5-4-3-2-1\n5 choses vues, 4 touchées, 3 entendues, 2 senties, 1 goûtée. Sort des spirales de panique.\n\n## Check-in binôme\nToutes les 30 min, regardez votre binôme dans les yeux : ''Corps ok ? Esprit ok ?''\n\n## Soin après action\nDécompresser dans les 24h. Douche chaude, repas complet, 8h de sommeil. Pas de réseaux sociaux pendant 12h.","mg":"# Mijoroa tsara\n\nNy tahotra dia vaovao, fa tsy fahalemena.\n\n## Fiainana 4-7-8\nMiaina 4s, tazony 7s, mivoaka 8s. Avereno indroa efatra.\n\n## Fametrahana 5-4-3-2-1\nLazao 5 hitanao, 4 tsapainao, 3 renao, 2 fofony, 1 tsapainao am-bava.\n\n## Fanamarinana ny mpiara-miasa\nIsaky ny 30 minitra, lazao: ''Tsara ny vatana? Tsara ny saina?''\n\n## Fikarakarana aorian''ny hetsika\nMandroa mafana, mihinana feno, matory 8 ora. Ialao ny tambajotra serasera mandritra ny 12 ora."}'::jsonb,
  'street_safety', 6, 'manual', true)
ON CONFLICT (slug) DO NOTHING;

INSERT INTO public.resources (slug, title, summary, body, category, read_minutes, source, published) VALUES
('communication-chiffree',
  '{"en":"Encrypted Communication Basics","fr":"Bases de la communication chiffrée","mg":"Fototry ny fifandraisana voabolisy"}'::jsonb,
  '{"en":"Choose the right tool, configure it correctly, and avoid common metadata leaks.","fr":"Choisir le bon outil, le configurer correctement, éviter les fuites de métadonnées.","mg":"Mifidiana fitaovana, alamino tsara, ialao ny famoahana metadata."}'::jsonb,
  '{"en":"# Encrypt by Default\n\n## Tool Choice\n- **Signal** — best general-purpose end-to-end encrypted messenger. Verified by independent audits.\n- **Element / Matrix** — for federated group coordination, self-hostable.\n- **Briar** — works without internet, peer-to-peer over Bluetooth/WiFi. Ideal when networks are throttled.\n\n## Critical Settings\n1. Enable **disappearing messages** (24h–7d depending on sensitivity)\n2. Verify **safety numbers** with key contacts in person\n3. Disable **message previews** on lock screen\n4. Set a strong **app PIN** separate from your phone unlock\n\n## Metadata Leaks to Avoid\n- Group names that reveal purpose — use neutral codes\n- Profile photos showing faces or locations\n- Linking your real phone number — use a secondary SIM if possible\n- Cloud backups (iCloud, Google Drive) — they break end-to-end encryption","fr":"# Chiffrez par défaut\n\n## Choix d''outil\n- **Signal** — meilleur messager E2E généraliste, audité.\n- **Element / Matrix** — coordination de groupe fédérée.\n- **Briar** — fonctionne sans internet, en P2P. Idéal en cas de bridage réseau.\n\n## Paramètres critiques\n1. Activez les **messages éphémères** (24h–7j)\n2. Vérifiez les **numéros de sécurité** en personne\n3. Désactivez les **aperçus** sur l''écran verrouillé\n4. Définissez un **code PIN d''application** distinct\n\n## Fuites à éviter\n- Noms de groupe révélateurs — utilisez des codes neutres\n- Photos de profil avec visages\n- Numéro réel — privilégiez une SIM secondaire\n- Sauvegardes cloud — elles cassent le chiffrement E2E","mg":"# Voabolisy hatrany\n\n## Safidio ny fitaovana\n- **Signal** — tsara indrindra ho an''ny fifandraisana voabolisy.\n- **Element / Matrix** — fandrindrana vondrona.\n- **Briar** — miasa tsy misy internet.\n\n## Lamina manan-danja\n1. Aelao ny **hafatra mandalo** (24 ora–7 andro)\n2. Hamarino ny **isa fiarovana** mifanatrika\n3. Vonoy ny **topimaso** amin''ny écran mihidy\n4. Mametraka **PIN** hafa\n\n## Famoahana hialana\n- Anaran''ny vondrona miharihary\n- Sary misy tarehy\n- Laharana finday tena — ampiasao SIM hafa\n- Tahiry cloud — manimba ny E2E"}'::jsonb,
  'digital_safety', 7, 'manual', true)
ON CONFLICT (slug) DO NOTHING;

INSERT INTO public.resources (slug, title, summary, body, category, read_minutes, source, published) VALUES
('securite-comptes-sociaux',
  '{"en":"Hardening Your Social Media Accounts","fr":"Sécuriser vos comptes de réseaux sociaux","mg":"Fiarovana ny kaonty serasera"}'::jsonb,
  '{"en":"Two-factor authentication, login alerts, session reviews, and what to do after a takeover attempt.","fr":"Double authentification, alertes de connexion, révision des sessions, et que faire après une tentative de piratage.","mg":"Fanamarinana roa, fampahafantarana fidirana, fanaraha-maso ny session, ary inona no atao raha misy fakana."}'::jsonb,
  '{"en":"# Lock Your Accounts\n\n## Step 1: Strong, Unique Passwords\nUse a password manager (Bitwarden is free and audited). Each account gets a 20+ character random password. Never reuse.\n\n## Step 2: 2FA — But Not SMS\nSMS 2FA can be bypassed via SIM swap. Use:\n- **Authenticator app** (Aegis on Android, Raivo on iOS)\n- **Hardware key** (YubiKey) for highest-risk accounts\n\n## Step 3: Audit Sessions Weekly\nEvery social platform shows active sessions. Log out anything unfamiliar. Change password immediately if you see a foreign device.\n\n## Step 4: Backup Codes\nGenerate and store backup 2FA codes offline (paper, encrypted USB). Without them, you can be locked out permanently.\n\n## Step 5: After a Takeover Attempt\n1. Change password from a clean device\n2. Revoke all sessions\n3. Rotate 2FA secrets\n4. Notify your network so impersonation attempts are caught\n5. Document the incident (screenshots, timestamps) for the legal team","fr":"# Verrouillez vos comptes\n\n## 1. Mots de passe forts et uniques\nUtilisez un gestionnaire (Bitwarden, gratuit et audité). 20+ caractères aléatoires par compte.\n\n## 2. 2FA — mais pas SMS\nLe SMS peut être contourné par SIM swap. Utilisez :\n- **App d''authentification** (Aegis, Raivo)\n- **Clé physique** (YubiKey) pour les comptes critiques\n\n## 3. Audit hebdomadaire des sessions\nDéconnectez tout appareil inconnu, changez le mot de passe immédiatement.\n\n## 4. Codes de secours\nGénérez et stockez hors-ligne (papier, USB chiffré).\n\n## 5. Après une tentative de piratage\n1. Changer le mot de passe depuis un appareil propre\n2. Révoquer toutes les sessions\n3. Régénérer les secrets 2FA\n4. Prévenir votre réseau\n5. Documenter (captures, horodatages)","mg":"# Hidio ny kaonty\n\n## 1. Tenimiafina matanjaka\nAmpiasao Bitwarden. Litera 20+ kisendrasendra.\n\n## 2. 2FA — fa tsy SMS\nMety ho takiana ny SMS. Ampiasao:\n- **App authentificateur** (Aegis, Raivo)\n- **Lakile fitaovana** (YubiKey)\n\n## 3. Fanaraha-maso isan-kerinandro\nVoaroahy ny fitaovana tsy fantatra.\n\n## 4. Kaody tahiry\nAtaovy an-taratasy na USB voabolisy.\n\n## 5. Aorian''ny andrana fakana\n1. Ovay ny tenimiafina amin''ny fitaovana madio\n2. Foano ny session rehetra\n3. Avereno ny 2FA\n4. Ampandreneso ny tambajotra\n5. Soraty ny zava-niseho"}'::jsonb,
  'digital_safety', 8, 'manual', true)
ON CONFLICT (slug) DO NOTHING;

INSERT INTO public.resources (slug, title, summary, body, category, read_minutes, source, published) VALUES
('observation-citoyenne-urnes',
  '{"en":"Citizen Election Observation","fr":"Observation citoyenne des urnes","mg":"Fanaraha-maso ny latsa-bato"}'::jsonb,
  '{"en":"How to observe a polling station legally, document irregularities, and submit verified reports.","fr":"Comment observer un bureau de vote légalement, documenter les irrégularités, et transmettre des rapports vérifiés.","mg":"Ahoana no fanarahana ny biraom-pifidianana, fanoratana ny tsy fetezana, sy fandefasana tatitra."}'::jsonb,
  '{"en":"# Watch the Vote\n\n## Before Election Day\n- Register as an observer with an accredited civil society organization\n- Carry your accreditation badge AND national ID\n- Memorize the legal hotline number\n- Know what is and is not allowed (no campaigning, no influencing voters)\n\n## At the Polling Station\n- **Arrive at opening** to verify ballot box is empty and sealed\n- Note the exact opening time, number of registered voters, and station officials present\n- Observe — do not interfere. Stand in the designated observer area.\n- If you witness an irregularity: write it down with **time, place, names of officials, and exact description**. Photo only if explicitly permitted.\n\n## Closing and Counting\n- Stay until the official count is finished\n- Note the count totals and demand a copy of the official tally sheet (PV)\n- Cross-check the PV against the totals you observed\n\n## Reporting\nSubmit a structured report within 24h: location, observer name, witnessed facts (with timestamps), supporting evidence. Avoid speculation. The legal team will aggregate and act.","fr":"# Surveiller le scrutin\n\n## Avant le jour J\n- Accréditez-vous via une OSC reconnue\n- Portez badge ET pièce d''identité\n- Mémorisez la hotline juridique\n- Connaissez les règles (interdit de faire campagne)\n\n## Au bureau de vote\n- **Arrivée à l''ouverture** : urne vide et scellée\n- Notez heure, électeurs inscrits, agents présents\n- Observez sans interférer\n- Irrégularité : notez **heure, lieu, noms, description exacte**. Photo uniquement si autorisée.\n\n## Clôture et dépouillement\n- Restez jusqu''au comptage final\n- Notez les résultats et demandez le PV\n- Recoupez avec ce que vous avez observé\n\n## Rapport\nSous 24h : lieu, observateur, faits horodatés, preuves. Pas de spéculation.","mg":"# Aoka horaisina an-tanana ny latsa-bato\n\n## Mialoha ny andro fifidianana\n- Misorato amin''ny fikambanana ekena\n- Mitondrà kara-panondro sy badge\n- Tadidio ny laharana ara-dalàna\n- Fantaro ny fitsipika\n\n## Eny amin''ny biraom-pifidianana\n- **Tongava amin''ny fanokafana**: hamarino fa foana ny vatam-pifidianana\n- Soraty ny ora, isan''ny mpifidy, sy ny mpiandraikitra\n- Mijere fa aza miditra an-tsehatra\n- Tsy fetezana: soraty ny **ora, toerana, anarana, fanazavana**\n\n## Famaranana sy fanisana\n- Mijanona mandra-pahavitan''ny fanisana\n- Soraty ny vokatra ary angataho ny PV\n\n## Tatitra\nLefaso ao anatin''ny 24 ora: toerana, anarana, zava-misy voasoratra, porofo."}'::jsonb,
  'know_your_rights', 9, 'manual', true)
ON CONFLICT (slug) DO NOTHING;

